// ============================================================
// Dashboard payload from Jobber (workflow static data).
// Monthly (top-level) + Weekly views, plus per-department
// metrics (Installations / Service) from one-off jobs.
// ============================================================
const sd = $getWorkflowStaticData('global');

function dedupe(arr, idKey) {
  const seen = new Set();
  const out = [];
  for (const x of (arr || [])) {
    const k = x && x[idKey];
    if (k == null) { out.push(x); continue; }
    if (seen.has(k)) continue;
    seen.add(k); out.push(x);
  }
  return out;
}

const quotes = dedupe(sd.qAll || [], 'id');
const requests = dedupe(sd.rAll || [], 'id');
const clients = dedupe(sd.cAll || [], 'id');
const invoices = dedupe(sd.iAll || [], 'id');
const jobs = dedupe(sd.jAll || [], 'id');
const recurring = dedupe(sd.recAll || [], 'id');
const DEPT_CUTOFF = new Date('2026-06-16T00:00:00Z').getTime(); // Install/Service clean-start (brief: no backfill before Jun 16)

const now = new Date();
const year = now.getFullYear();
const MONTH_NAMES = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
const months = MONTH_NAMES.slice();

// Vancouver-local Y/M/D for a date string.
function vparts(dateStr) {
  if (!dateStr) return null;
  const d = new Date(dateStr);
  if (isNaN(d.getTime())) return null;
  const p = new Intl.DateTimeFormat('en-US', { timeZone: 'America/Vancouver', year: 'numeric', month: 'numeric', day: 'numeric' }).formatToParts(d);
  return { y: Number(p.find(x => x.type === 'year').value), m: Number(p.find(x => x.type === 'month').value), d: Number(p.find(x => x.type === 'day').value) };
}

function monthOf(dateStr) {
  const p = vparts(dateStr);
  if (!p || p.y !== year) return null;
  return MONTH_NAMES[p.m - 1];
}

// WEEK helpers — weeks start Monday; label = that Monday's "MMM D".
function dayNum(y, m, d) { return Math.floor(Date.UTC(y, m - 1, d) / 86400000); }
function mondayDn(y, m, d) {
  const dow = new Date(Date.UTC(y, m - 1, d)).getUTCDay();
  const off = dow === 0 ? 6 : dow - 1;
  return dayNum(y, m, d) - off;
}
function labelOfDn(dn) {
  const dt = new Date(dn * 86400000);
  return MONTH_NAMES[dt.getUTCMonth()] + ' ' + dt.getUTCDate();
}
function weekOf(dateStr) {
  const p = vparts(dateStr);
  if (!p || p.y !== year) return null;
  return labelOfDn(mondayDn(p.y, p.m, p.d));
}
const startDn = mondayDn(year, 1, 1);
const tp = vparts(now.toISOString());
const endDn = mondayDn(year, 12, 31);
const weeks = [];
for (let dn = startDn; dn <= endDn; dn += 7) weeks.push(labelOfDn(dn));
const currentMonth = MONTH_NAMES[tp.m - 1];
const currentWeek = labelOfDn(mondayDn(tp.y, tp.m, tp.d));

function personOf(quote) {
  return (quote.salesperson && quote.salesperson.name && quote.salesperson.name.full || '').trim() || 'Unassigned';
}

// Read the "Type of Job" dropdown custom field on a job ("Install" / "Service" / "" ...).
function jobTypeOf(job) {
  const cfs = (job && job.customFields) || [];
  for (const cf of cfs) {
    if (cf && cf.label === 'Type of Job') return (cf.valueDropdown || '').trim();
  }
  return '';
}

function buildView(labelOf, labels) {
  const has = {};
  labels.forEach(l => { has[l] = true; });
  function empty() { const o = {}; labels.forEach(l => { o[l] = 0; }); return o; }
  function ensure(obj, p) { if (!obj[p]) obj[p] = empty(); return obj[p]; }

  const revenueProduced = empty();
  const invoicesIssued = empty();
  const invoiceCount = empty();
  for (const inv of invoices) { const k = labelOf(inv.issuedDate); if (k && has[k]) { const a = inv.amounts || {}; const t = parseFloat(a.total) || 0; invoicesIssued[k] += t; invoiceCount[k] += 1; revenueProduced[k] += t - (parseFloat(a.invoiceBalance) || 0); } }

  const cashCollected = empty();

  const newLeads = empty();
  for (const c of clients) { const k = labelOf(c.createdAt); if (k && has[k]) newLeads[k] += 1; }

  const newRequests = empty();
  for (const r of requests) { const k = labelOf(r.createdAt); if (k && has[k]) newRequests[k] += 1; }

  const quotesSentTotal = empty();
  const quotesSentByPerson = {};
  const quotesConvertedTotal = empty();
  const quotesConvertedByPerson = {};
  const convertedDollarsTotal = empty();
  const convertedDollarsByPerson = {};

  for (const q of quotes) {
    const status = (q.quoteStatus || '').toUpperCase();
    const person = personOf(q);
    const amount = parseFloat(q.amounts && q.amounts.total) || 0;
    const sk = labelOf(q.sentAt);
    if (sk && has[sk]) { quotesSentTotal[sk] += 1; ensure(quotesSentByPerson, person)[sk] += 1; }
    if (status === 'CONVERTED') {
      const ck = labelOf(q.transitionedAt);
      if (ck && has[ck]) {
        quotesConvertedTotal[ck] += 1;
        ensure(quotesConvertedByPerson, person)[ck] += 1;
        convertedDollarsTotal[ck] += amount;
        ensure(convertedDollarsByPerson, person)[ck] += amount;
      }
    }
  }

  function round2(map) { for (const k of Object.keys(map)) map[k] = Math.round(map[k] * 100) / 100; return map; }
  round2(revenueProduced); round2(invoicesIssued); round2(cashCollected); round2(convertedDollarsTotal);

  const allPersons = Array.from(new Set(Object.keys(quotesSentByPerson).concat(Object.keys(quotesConvertedByPerson))));
  for (const p of allPersons) { ensure(quotesSentByPerson, p); ensure(quotesConvertedByPerson, p); ensure(convertedDollarsByPerson, p); }
  for (const p of allPersons) round2(convertedDollarsByPerson[p]);

  function rate(conv, sent) { const o = {}; for (const k of labels) o[k] = (sent[k] || 0) > 0 ? Math.round((conv[k] / sent[k]) * 1000) / 10 : 0; return o; }
  const conversionRateTotal = rate(quotesConvertedTotal, quotesSentTotal);
  const conversionRateByPerson = {};
  for (const p of allPersons) conversionRateByPerson[p] = rate(quotesConvertedByPerson[p], quotesSentByPerson[p]);

  function avg(dollars, conv) { const o = {}; for (const k of labels) o[k] = (conv[k] || 0) > 0 ? Math.round((dollars[k] / conv[k]) * 100) / 100 : 0; return o; }
  const avgSaleTotal = avg(convertedDollarsTotal, quotesConvertedTotal);
  const avgSaleByPerson = {};
  for (const p of allPersons) avgSaleByPerson[p] = avg(convertedDollarsByPerson[p], quotesConvertedByPerson[p]);

  // One-off job operations: New jobs (count), Job revenue (sum of totals), Avg job size — all one-off jobs by createdAt (full year).
  const newJobs = empty();
  const jobRevenue = empty();
  const avgJobSize = empty();
  for (const j of jobs) {
    if ((j.jobType || '').toUpperCase() !== 'ONE_OFF') continue;
    const k = labelOf(j.createdAt);
    if (!k || !has[k]) continue;
    newJobs[k] += 1;
    jobRevenue[k] += parseFloat(j.jobCosting && j.jobCosting.totalRevenue) || 0; // Jobber's "Job revenue" (job-costing), not the "Total revenue" (job.total)
  }
  round2(jobRevenue);
  for (const k of labels) avgJobSize[k] = (newJobs[k] || 0) > 0 ? Math.round((jobRevenue[k] / newJobs[k]) * 100) / 100 : 0;

  // Departments (one-off jobs): Installations + Service. Revenue + jobs completed by completedAt; avg ticket = revenue / jobs.
  const deptDefs = [{ key: 'installations', type: 'Install' }, { key: 'service', type: 'Service' }];
  const departments = {};
  for (const d of deptDefs) departments[d.key] = { revenue: empty(), jobsCompleted: empty(), avgTicket: empty() };
  for (const j of jobs) {
    if ((j.jobType || '').toUpperCase() !== 'ONE_OFF') continue;
    if (!j.createdAt || new Date(j.createdAt).getTime() < DEPT_CUTOFF) continue; // clean-start: only jobs created from Jun 16
    const t = jobTypeOf(j);
    const def = deptDefs.find((x) => x.type === t);
    if (!def) continue;
    const k = labelOf(j.completedAt); // count/bucket completed jobs
    if (!k || !has[k]) continue;
    departments[def.key].revenue[k] += parseFloat(j.total) || 0;
    departments[def.key].jobsCompleted[k] += 1;
  }
  for (const d of deptDefs) {
    round2(departments[d.key].revenue);
    const rev = departments[d.key].revenue, cnt = departments[d.key].jobsCompleted, at = departments[d.key].avgTicket;
    for (const k of labels) at[k] = (cnt[k] || 0) > 0 ? Math.round((rev[k] / cnt[k]) * 100) / 100 : 0;
  }

  // Maintenance (recurring jobs): each COMPLETED visit = one job completed; revenue = sum of that visit's line items, bucketed by completedAt.
  { const maint = { revenue: empty(), jobsCompleted: empty(), avgTicket: empty() };
  for (const j of recurring) {
    const vs = (j.visits && j.visits.nodes) || [];
    for (const vis of vs) {
      if (!vis || !vis.isComplete) continue;
      const k = labelOf(vis.completedAt);
      if (!k || !has[k]) continue;
      const lis = (vis.lineItems && vis.lineItems.nodes) || [];
      let rv = 0; for (const li of lis) rv += parseFloat(li.totalPrice) || 0;
      maint.revenue[k] += rv; maint.jobsCompleted[k] += 1;
    }
  }
  round2(maint.revenue);
  for (const k of labels) maint.avgTicket[k] = (maint.jobsCompleted[k] || 0) > 0 ? Math.round((maint.revenue[k] / maint.jobsCompleted[k]) * 100) / 100 : 0;
  departments.maintenance = maint; }

  return {
    revenueProduced, invoicesIssued, invoiceCount, cashCollected, newLeads, newRequests,
    newJobs, jobRevenue, avgJobSize,
    quotesSent: { total: quotesSentTotal, byPerson: quotesSentByPerson },
    quotesConverted: { total: quotesConvertedTotal, byPerson: quotesConvertedByPerson },
    conversionRate: { total: conversionRateTotal, byPerson: conversionRateByPerson },
    convertedDollars: { total: convertedDollarsTotal, byPerson: convertedDollarsByPerson },
    avgSale: { total: avgSaleTotal, byPerson: avgSaleByPerson },
    departments
  };
}

const monthly = buildView(monthOf, months);
const weekly = buildView(weekOf, weeks);

// Accounts Receivable — matches Jobber's Aged Receivables report: OVERDUE invoices only (dueDate < today), aged by due date, using outstanding Balance.
const nowMs = now.getTime();
let arTotal = 0, arOver30 = 0;
for (const inv of invoices) {
  if ((inv.invoiceStatus || '') !== 'past_due') continue; // Jobber's Aged Receivables counts past_due invoices only
  const bal = parseFloat(inv.amounts && inv.amounts.invoiceBalance) || 0;
  if (bal <= 0) continue;
  arTotal += bal;
  const dueMs = inv.dueDate ? new Date(inv.dueDate).getTime() : 0;
  if (dueMs && (nowMs - dueMs) > 30 * 86400000) arOver30 += bal; // late by more than 30 days
}
arTotal = Math.round(arTotal * 100) / 100; arOver30 = Math.round(arOver30 * 100) / 100;
const receivables = { total: arTotal, over30: arOver30, over30Pct: arTotal > 0 ? Math.round((arOver30 / arTotal) * 1000) / 10 : 0 };

return [Object.assign({
  months, weeks, weekly, currentMonth, currentWeek, receivables,
  _debug: { quotes: quotes.length, requests: requests.length, clients: clients.length, invoices: invoices.length, jobs: jobs.length, recurring: recurring.length, weeks: weeks.length }
}, monthly)];
